-- create a table, insert a row, query it back
CREATE TABLE users (id serial PRIMARY KEY, email text UNIQUE NOT NULL);
INSERT INTO users (email) VALUES ('ada@example.com');
SELECT id, email FROM users WHERE email = 'ada@example.com';

-- a rigid id but a flexible JSONB payload, both queryable
CREATE TABLE events (
  id serial PRIMARY KEY,
  kind text NOT NULL,
  payload jsonb NOT NULL
);
CREATE INDEX ON events USING gin (payload);
SELECT * FROM events WHERE payload->>'user_id' = '42';

CREATE TABLE customers (
  id serial PRIMARY KEY,
  name text NOT NULL,
  email text UNIQUE NOT NULL
);

CREATE TABLE orders (
  id serial PRIMARY KEY,
  customer_id int NOT NULL REFERENCES customers(id),
  total numeric(10,2) NOT NULL CHECK (total >= 0),
  created_at timestamptz NOT NULL DEFAULT now()
);

INSERT INTO customers (name, email)
VALUES ('Ada Lovelace', 'ada@example.com')
RETURNING id;            -- returns the generated id

INSERT INTO orders (customer_id, total)
VALUES (1, 49.99), (1, 12.50);

SELECT * FROM orders WHERE customer_id = 1;

-- queries filter orders by customer_id a lot
CREATE INDEX idx_orders_customer ON orders (customer_id);

-- confirm the planner now uses it
EXPLAIN ANALYZE
SELECT * FROM orders WHERE customer_id = 1;
-- expect 'Index Scan using idx_orders_customer'

